function execute(input) {
  function num(v, d) {
    const n = Number(v);
    return Number.isFinite(n) ? n : d;
  }
  const population = num(input.population, 0);
  const foodMonthsReserve = num(input.foodMonthsReserve, 0);
  const powerKw = num(input.powerKw, 0);
  const waterLPerDay = num(input.waterLPerDay, 0);
  const modules = num(input.modules, 0);
  const lifeSupport = num(input.lifeSupport, 0);

  const arcadia = { terrainRisk: 9, constructionEase: 10, iceValue: 9, scienceValue: 4 };
  const valles = { terrainRisk: 3, constructionEase: 3, iceValue: 2, scienceValue: 10 };

  function score(site) {
    const reliability = (site.terrainRisk * 0.5) + (site.constructionEase * 0.5);
    const resourceSupport = Math.min(10, (site.iceValue * 0.6) + (waterLPerDay / 100) * 0.4);
    const habitatSupport = Math.min(10, (powerKw / 50) + (lifeSupport / 20) + (modules / 2));
    const colonyBuffer = Math.min(10, (foodMonthsReserve / 2) + (population / 50));
    return (0.45 * reliability) + (0.35 * resourceSupport) + (0.20 * site.scienceValue) + (0.05 * habitatSupport) + (0.05 * colonyBuffer);
  }

  const arcadiaScore = score(arcadia);
  const vallesScore = score(valles);
  const recommendation = arcadiaScore >= vallesScore ? "Arcadia Planitia" : "Valles Marineris rim";
  const rationale = recommendation === "Arcadia Planitia"
    ? "Lower terrain risk and easier construction dominate first-settlement needs."
    : "Scientific value outweighs operational risk.";

  return {
    arcadiaScore: Number(arcadiaScore.toFixed(2)),
    vallesScore: Number(vallesScore.toFixed(2)),
    recommendation,
    rationale
  };
}
